169→function hasApprovedPlan(planPath: string): boolean {
170→  if (!existsSync(planPath)) {
171→    return false;
172→  }
173→
174→  try {
175→    const content = readFileSync(planPath, "utf-8");
176→    const hasCompletePlan = PLAN_STATUS_REGEX.test(content);
177→    const hasReviewPass = REVIEW_STATUS_REGEX.test(content);
178→    const hasHumanApproval = APPROVAL_STATUS_REGEX.test(content);
179→    if (!hasCompletePlan || !hasReviewPass || !hasHumanApproval) {
180→      return false;
181→    }
182→
183→    const marker = extractLatestAutoReviewMarker(content);
184→    if (!marker || marker.verdict !== "pass") {
185→      return false;
186→    }
187→
188→    const actualHash = computePlanHash(content);
189→    return marker.hash === actualHash;
190→  } catch {
191→    return false;
192→  }
193→}
