195→function getTargetFilePath(
196→  tool_name: string,
197→  tool_input: unknown,
198→): string | null {
199→  if (!isRecord(tool_input)) {
200→    return null;
201→  }
202→
203→  if (
204→    (tool_name === "Write" ||
205→      tool_name === "Edit" ||
206→      tool_name === "MultiEdit") &&
207→    typeof tool_input.file_path === "string"
208→  ) {
209→    return tool_input.file_path;
210→  }
211→
212→  if (
213→    tool_name === "NotebookEdit" &&
214→    typeof tool_input.notebook_path === "string"
215→  ) {
216→    return tool_input.notebook_path;
217→  }
218→
219→  return null;
220→}
