222→async function analyzeBashWrite(command: string): Promise<WriteAnalysis> {
223→  const result = await extractCommandsStructured(command);
224→  const commands = result.individualCommands;
225→
226→  const targets: string[] = [];
227→  let isWriteLike = false;
228→
229→  for (const cmd of commands) {
230→    const analysis = analyzeSingleCommand(cmd);
231→    if (analysis.isWriteLike) {
232→      isWriteLike = true;
233→      targets.push(...analysis.targets);
234→    }
235→  }
236→
237→  return {
238→    isWriteLike,
239→    targets: dedupe(targets),
240→  };
241→}
