243→function analyzeSingleCommand(command: string): WriteAnalysis {
244→  const words = splitShellWords(command);
245→  if (words.length === 0) {
246→    return { isWriteLike: false, targets: [] };
247→  }
248→
249→  const redirectionTargets = extractRedirectionTargets(words);
250→  const main = extractMainCommand(words);
251→  if (!main) {
252→    if (redirectionTargets.length > 0) {
253→      return { isWriteLike: true, targets: redirectionTargets };
254→    }
255→    return { isWriteLike: false, targets: [] };
256→  }
257→
258→  const { name, args } = main;
259→  const lower = name.toLowerCase();
260→  const commandTargets: string[] = [];
261→  let isWriteLike = redirectionTargets.length > 0;
262→
263→  if (lower === "tee") {
264→    const files = args.filter((arg) => !arg.startsWith("-"));
265→    if (files.length > 0) {
266→      isWriteLike = true;
267→      commandTargets.push(...files);
268→    }
269→  } else if (["touch", "mkdir", "rm", "rmdir", "truncate"].includes(lower)) {
270→    const files = args.filter((arg) => !arg.startsWith("-"));
271→    if (files.length > 0) {
272→      isWriteLike = true;
273→      commandTargets.push(...files);
274→    }
275→  } else if (["cp", "mv", "install"].includes(lower)) {
276→    const positional = args.filter((arg) => !arg.startsWith("-"));
277→    if (positional.length >= 2) {
278→      isWriteLike = true;
279→      commandTargets.push(positional[positional.length - 1] || "");
280→    }
281→  } else if (lower === "sed" || lower === "perl") {
282→    if (args.some((arg) => arg === "-i" || arg.startsWith("-i"))) {
283→      const positional = args.filter((arg) => !arg.startsWith("-"));
284→      const last = positional[positional.length - 1];
285→      if (last) {
286→        isWriteLike = true;
287→        commandTargets.push(last);
288→      }
289→    }
290→  }
291→
292→  if (!isWriteLike) {
293→    return { isWriteLike: false, targets: [] };
294→  }
295→
296→  return {
297→    isWriteLike: true,
298→    targets: dedupe([...redirectionTargets, ...commandTargets]).filter(
299→      (target) => target.length > 0,
300→    ),
301→  };
302→}
303→
304→function extractMainCommand(
305→  words: string[],
306→): { name: string; args: string[] } | null {
307→  let index = 0;
308→  while (index < words.length) {
309→    const token = words[index];
310→    if (!token) {
311→      index += 1;
312→      continue;
313→    }
314→    if (isVariableAssignment(token)) {
315→      index += 1;
316→      continue;
317→    }
318→    return {
319→      name: token,
320→      args: words.slice(index + 1),
321→    };
322→  }
323→  return null;
324→}
325→
326→function isVariableAssignment(token: string): boolean {
327→  return /^[A-Za-z_][A-Za-z0-9_]*=/.test(token);
328→}
329→
330→function extractRedirectionTargets(words: string[]): string[] {
331→  const targets: string[] = [];
332→
333→  for (let i = 0; i < words.length; i++) {
334→    const token = words[i];
335→    if (!token) {
336→      continue;
337→    }
338→
339→    if (isRedirectionToken(token)) {
340→      const next = words[i + 1];
341→      if (next && !next.startsWith("&")) {
342→        targets.push(next);
343→      }
344→      continue;
345→    }
346→
347→    const inline = token.match(/^(?:\d*>>?|\d*>\|)(.+)$/);
348→    if (inline?.[1] && !inline[1].startsWith("&")) {
349→      targets.push(inline[1]);
350→    }
351→  }
352→
353→  return targets;
354→}
355→
356→function isRedirectionToken(token: string): boolean {
357→  return /^(?:\d*>>?|\d*>\|)$/.test(token);
358→}
359→
360→function splitShellWords(command: string): string[] {
361→  const matches = command.match(/"[^"]*"|'[^']*'|\S+/g) || [];
362→  return matches.map((word) => stripQuotes(word));
363→}
364→
365→function stripQuotes(value: string): string {
366→  if (
367→    (value.startsWith('"') && value.endsWith('"')) ||
368→    (value.startsWith("'") && value.endsWith("'"))
369→  ) {
370→    return value.slice(1, -1);
371→  }
372→  return value;
373→}
374→
375→function computePlanHash(content: string): string {
376→  const stripped = content.replace(REVIEW_MARKER_REGEX, "").trimEnd();
377→  return createHash("sha256").update(stripped, "utf-8").digest("hex");
378→}
379→
380→function extractLatestAutoReviewMarker(
381→  content: string,
382→): AutoReviewMarker | null {
383→  const matches = content.match(REVIEW_MARKER_REGEX);
384→  if (!matches || matches.length === 0) {
385→    return null;
386→  }
387→
388→  const latest = matches[matches.length - 1];
389→  if (!latest) {
390→    return null;
391→  }
392→
393→  let verdict = "";
394→  let hash = "";
395→  const fields = latest.matchAll(/(\w+)=([^;]+)/g);
396→  for (const field of fields) {
397→    const key = field[1]?.trim();
398→    const value = field[2]?.trim();
399→    if (!key || !value) {
400→      continue;
401→    }
402→    if (key === "verdict") {
403→      verdict = value;
404→    } else if (key === "hash") {
405→      hash = value;
406→    }
407→  }
408→
409→  if (verdict.length === 0 || hash.length === 0) {
410→    return null;
411→  }
412→
413→  return { verdict, hash };
414→}
415→
416→function isRecord(value: unknown): value is Record<string, unknown> {
417→  return typeof value === "object" && value !== null;
418→}
419→
420→function dedupe(values: string[]): string[] {
421→  return [...new Set(values)];
422→}
423→
424→export default hook;
425→
426→if (import.meta.main) {
427→  const { runHook } = await import("cc-hooks-ts");
428→  await runHook(hook);
429→}
